import sys
def get_console():
    """Safe console access that works everywhere"""
    try:
        from rich.console import Console
        return Console()
    except ImportError:
        class FallbackConsole:
            def print(self, *args, **kwargs):
                print(*args, **kwargs)
        return FallbackConsole()

console = get_console()

# Debug logging to file (fail‑safe)
# Prefer a writable local path; never raise during logging
try:
    DEFAULT_DEBUG_LOG = (Path.cwd() / "tool_debug.log").resolve()
except Exception:
    DEFAULT_DEBUG_LOG = Path("/tmp/tool_debug.log")

def log_debug(msg):
    """Write debug messages to a local log without throwing.
    Falls back to /tmp if the current directory is not writable.
    """
    path_candidates = [DEFAULT_DEBUG_LOG]
    try:
        # Also allow env override for debugging
        env_path = os.environ.get('OPENCODE_TOOL_DEBUG_LOG')
        if env_path:
            path_candidates.insert(0, Path(env_path))
    except Exception:
        pass
    for p in path_candidates:
        try:
            p.parent.mkdir(parents=True, exist_ok=True)
            with open(p, 'a', encoding='utf-8') as f:
                f.write(f"{msg}\n")
                f.flush()
            return
        except Exception:
            continue
    # Absolute last resort: print; never crash tool flows due to logging
    try:
        print(str(msg))
    except Exception:
        pass

def get_mount_points():
    mount_points = set()
    try:
        with open('/proc/self/mountinfo', 'r') as f:
            for line in f:
                parts = line.split()
                if len(parts) >= 5:
                    mount_point = parts[4]
                    # Unescape octal escapes in mount_point
                    mount_point = mount_point.encode('utf-8').decode('unicode-escape')
                    mount_points.add(os.path.normpath(mount_point))
    except Exception:
        pass
    return mount_points

class ToolRiskLevel(Enum):
    SAFE = "safe"
    LOW = "low"
    MEDIUM = "medium"
    HIGH = "high"
    CRITICAL = "critical"

@dataclass
class ToolOperation:
    tool_name: str
    operation: str
    params: Dict[str, Any]
    risk_level: ToolRiskLevel = ToolRiskLevel.LOW
    confirmation_required: bool = False
    description: Optional[str] = None

@dataclass
class ToolResult:
    """Result from tool execution"""
    success: bool
    output: str
    error: Optional[str] = None
    data: Optional[Dict] = None

class BaseTool:
    """Base class for all tools"""

    def __init__(self, config: ToolsConfig):
        self.config = config
        # Initialize working_dir - can be updated by ToolManager
        self.working_dir = Path.cwd().resolve()

    def _validate_path(self, file_path: str) -> bool:
        log_debug(f"_validate_path called with file_path='{file_path}'")
        log_debug(f"self.working_dir='{self.working_dir}'")
        try:
            # Convert to absolute path and resolve
            # If path is relative, resolve it relative to working_dir first
            file_path_obj = Path(file_path)
            if file_path_obj.is_absolute():
                abs_path = file_path_obj.resolve()
                log_debug(f"_validate_path - absolute path: abs_path='{abs_path}'")
            else:
                # Relative path - resolve relative to working directory
                abs_path = (self.working_dir / file_path).resolve()
                log_debug(f"_validate_path - relative path: abs_path='{abs_path}'")

            # Check if the path is within the working directory
            try:
                abs_path.relative_to(self.working_dir)
                log_debug(f"_validate_path - '{abs_path}' is relative to '{self.working_dir}'")
                return True
            except ValueError:
                log_debug(f"_validate_path - '{abs_path}' is NOT relative to '{self.working_dir}'")
                return False
        except Exception as e:
            log_debug(f"_validate_path - Exception: {e}")
            return False
    
    def _safe_path(self, file_path: str) -> Optional[Path]:
        """Get a safe path object if the path is valid"""
        if not self._validate_path(file_path):
            return None
        # Resolve relative to self.working_dir, not OS CWD
        file_path_obj = Path(file_path)
        if file_path_obj.is_absolute():
            return file_path_obj.resolve()
        else:
            return (self.working_dir / file_path).resolve()
    
    async def execute(self, **kwargs) -> ToolResult:
        """Execute the tool with given parameters"""
        raise NotImplementedError

class FileReadTool(BaseTool):
    """Tool for reading files"""
    
    async def execute(self, file_path: str, start_line: Optional[int] = None,
                     end_line: Optional[int] = None) -> ToolResult:
        log_debug(f"=== FileReadTool.execute START ===")
        log_debug(f"  file_path='{file_path}'")
        try:
            # Validate path is within working directory
            safe_path = self._safe_path(file_path)
            log_debug(f"  safe_path='{safe_path}'")
            if safe_path is None:
                log_debug(f"  ERROR: safe_path is None, access denied")
                return ToolResult(
                    success=False,
                    output="",
                    error=f"Access denied: {file_path} is outside the working directory"
                )

            log_debug(f"  Checking if file exists: {safe_path.exists()}")
            if not safe_path.exists():
                # Optional case-insensitive fallback when user passed a relative single-segment filename
                try:
                    fp = str(file_path)
                    if '/' not in fp and '\\' not in fp:
                        candidates = list(self.working_dir.iterdir())
                        match = None
                        for c in candidates:
                            try:
                                if c.is_file() and c.name.lower() == Path(fp).name.lower():
                                    match = c; break
                            except Exception:
                                continue
                        if match is not None:
                            safe_path = match.resolve()
                            log_debug(f"  Case-insensitive match used: {safe_path}")
                except Exception as _e:
                    log_debug(f"  Case-insensitive fallback failed: {_e}")
                if not safe_path.exists():
                    log_debug(f"  ERROR: File does not exist (after fallback)")
                    return ToolResult(success=False, output="", error=f"File not found: {file_path}")
            
            log_debug(f"  Reading file content...")
            content = safe_path.read_text(encoding='utf-8')
            log_debug(f"  Read {len(content)} chars successfully")

            if start_line is not None or end_line is not None:
                lines = content.split('\n')
                start = (start_line - 1) if start_line else 0
                end = end_line if end_line else len(lines)
                content = '\n'.join(lines[start:end])

            log_debug(f"  Returning success with {len(content)} chars")
            return ToolResult(
                success=True,
                output=content,
                data={"file_path": file_path, "size": len(content)}
            )

        except Exception as e:
            log_debug(f"  EXCEPTION: {e}")
            import traceback
            log_debug(f"  Traceback: {traceback.format_exc()}")
            return ToolResult(success=False, output="", error=str(e))

class FileWriteTool(BaseTool):
    """Tool for writing files"""
    
    async def execute(self, file_path: str, content: str,
                     create_dirs: bool = True) -> ToolResult:
        print(f"DEBUG: FileWriteTool.execute called. Loaded from: {__file__}")
        try:
            # Validate path is within working directory
            safe_path = self._safe_path(file_path)
            if safe_path is None:
                print(f"DEBUG: FileWriteTool - safe_path is None. Returning error.")
                return ToolResult(
                    success=False,
                    output="",
                    error=f"Access denied: {file_path} is outside the working directory"
                )

            # Check if file exists (overwrite operation needs confirmation)
            file_exists = safe_path.exists()
            if file_exists:
                # Request confirmation for overwrite operation
                operation_info = OperationInfo(
                    operation_name="Overwrite File",
                    description=f"Overwrite existing file: {file_path}",
                    risk_level=RiskLevel.MEDIUM,
                    affected_items=[file_path],
                    consequences=["Existing file content will be overwritten. Data may be lost if not backed up."],
                    reversible=False, # FileWriteTool does not implement explicit backup/restore
                    backup_available=False, # FileWriteTool does not implement explicit backup/restore
                    context_data={"file_size": len(content)}
                )
                if not confirm_operation(operation_info):
                    return ToolResult(
                        success=False,
                        output="",
                        error="Operation cancelled by user - file overwrite not confirmed"
                    )

            if create_dirs:
                print(f"DEBUG: FileWriteTool - create_dirs is True. safe_path='{safe_path}'")
                parent_path = safe_path.parent
                print(f"DEBUG: FileWriteTool - parent_path='{parent_path}'")
                if not self._validate_path(str(parent_path)):
                    print(f"DEBUG: FileWriteTool - _validate_path for parent_path returned False. Returning error.")
                    return ToolResult(
                        success=False,
                        output="",
                        error=f"Access denied: parent directory {parent_path} is outside the working directory"
                    )
                parent_path.mkdir(parents=True, exist_ok=True)

            safe_path.write_text(content, encoding='utf-8')
            
            return ToolResult(
                success=True,
                output=f"File written successfully: {file_path}",
                data={"file_path": file_path, "size": len(content)}
            )
            
        except Exception as e:
            return ToolResult(success=False, output="", error=str(e))

class FileEditTool(BaseTool):
    """Tool for editing files"""
    
    async def execute(self, file_path: str, old_text: str, new_text: str) -> ToolResult:
        try:
            # Validate path is within working directory
            safe_path = self._safe_path(file_path)
            if safe_path is None:
                return ToolResult(
                    success=False, 
                    output="",
                    error=f"Access denied: {file_path} is outside the working directory"
                )
            
            if not safe_path.exists():
                return ToolResult(success=False, output="", error=f"File not found: {file_path}")
            
            content = safe_path.read_text(encoding='utf-8')
            
            if old_text not in content:
                return ToolResult(
                    success=False,
                    output="", # Added missing output argument
                    error=f"Text not found in file: {old_text[:50]}..."
                )

            # Request confirmation for file modification
            operation_info = OperationInfo(
                operation_name="Edit File",
                description=f"Modify file: {file_path}",
                risk_level=RiskLevel.LOW,
                affected_items=[file_path],
                consequences=["File content will be modified."],
                reversible=True, # Edits are generally reversible if original content is known
                backup_available=False, # No explicit backup/restore in FileEditTool
                context_data={"old_text_length": len(old_text), "new_text_length": len(new_text)}
            )
            if not confirm_operation(operation_info):
                return ToolResult(
                    success=False,
                    output="",
                    error="Operation cancelled by user - file edit not confirmed"
                )

            new_content = content.replace(old_text, new_text)
            safe_path.write_text(new_content, encoding='utf-8')
            
            return ToolResult(
                success=True,
                output=f"File edited successfully: {file_path}",
                data={"file_path": file_path, "changes": 1}
            )
            
        except Exception as e:
            return ToolResult(success=False, output="", error=str(e))
            
        except Exception as e:
            return ToolResult(success=False, output="", error=str(e))

class BashExecuteTool(BaseTool):
    """Tool for executing bash commands"""

    def __init__(self, config: ToolsConfig):
        super().__init__(config)
        self.command_policy = CommandPolicy(config.bash.allowed_commands)

    async def execute(self, command: str, cwd: Optional[str] = None) -> ToolResult:
        try:
            # Validate and set working directory
            if cwd is not None:
                if not self._validate_path(cwd):
                    return ToolResult(
                        success=False,
                        output="",
                        error=f"Access denied: {cwd} is outside the working directory"
                    )
                execution_cwd = str(self._safe_path(cwd))
            else:
                execution_cwd = str(self.working_dir)

            # Parse command safely using CommandPolicy
            try:
                argv = self.command_policy.parse_command_safe(command)
            except ValueError as e:
                return ToolResult(
                    success=False,
                    output="",
                    error=f"Command validation failed: {e}"
                )

            # Check for potentially dangerous commands that need confirmation
            dangerous_patterns = ['rm', 'delete', 'format', 'dd', 'sudo']
            command_lower = command.lower()
            is_dangerous = any(pattern in command_lower for pattern in dangerous_patterns)

            if is_dangerous:
                # Request confirmation for dangerous command
                operation_info = OperationInfo(
                    operation_name="Execute Dangerous Command",
                    description=f"Execute potentially dangerous command: {command}",
                    risk_level=RiskLevel.HIGH,
                    affected_items=[execution_cwd],
                    context_data={"command": command}
                )
                if not confirm_operation(operation_info):
                    return ToolResult(
                        success=False,
                        output="",
                        error="Operation cancelled by user - dangerous command execution not confirmed"
                    )

            # Execute command using secure policy
            result = await self.command_policy.execute_safe(
                argv=argv,
                cwd=execution_cwd,
                timeout=self.config.bash.timeout,
                risk_level="MEDIUM"
            )

            return ToolResult(
                success=result['success'],
                output=result['stdout'],
                error=result['stderr'] if not result['success'] else None
            )

        except Exception as e:
            return ToolResult(
                success=False,
                output="",
                error=f"Command execution failed: {e}"
            )

class GrepSearchTool(BaseTool):
    """Tool for searching in files using grep-like functionality"""
    
    async def execute(self, pattern: str, path: str = ".", 
                     file_pattern: Optional[str] = None,
                     case_sensitive: bool = True) -> ToolResult:
        try:
            # Validate search path is within working directory
            safe_search_path = self._safe_path(path)
            if safe_search_path is None:
                return ToolResult(
                    success=False, 
                    output="",
                    error=f"Access denied: {path} is outside the working directory"
                )
            
            if not safe_search_path.exists():
                return ToolResult(success=False, output="", error=f"Path not found: {path}")
            
            results = []
            
            if safe_search_path.is_file():
                files = [safe_search_path]
            else:
                # Find files matching pattern
                if file_pattern:
                    files = list(safe_search_path.rglob(file_pattern))
                else:
                    files = [f for f in safe_search_path.rglob("*") if f.is_file()]
            
            flags = 0 if case_sensitive else re.IGNORECASE
            regex = re.compile(pattern, flags)
            
            for file_path in files:
                try:
                    # Double-check that each file is within working directory
                    if not self._validate_path(str(file_path)):
                        continue
                    
                    if file_path.suffix in ['.pyc', '.pyo', '.pyd']:
                        continue
                    
                    content = file_path.read_text(encoding='utf-8')
                    lines = content.split('\n')
                    
                    for line_num, line in enumerate(lines, 1):
                        if regex.search(line):
                            results.append({
                                "file": str(file_path),
                                "line": line_num,
                                "content": line.strip()
                            })
                            
                except (UnicodeDecodeError, PermissionError):
                    continue
            
            output = "\n".join([
                f"{r['file']}:{r['line']}:{r['content']}"
                for r in results
            ])
            
            return ToolResult(
                success=True,
                output=output,
                data={"matches": len(results), "results": results}
            )
            
        except Exception as e:
            return ToolResult(success=False, output="", error=str(e))

class GitOperationsTool(BaseTool):
    """Tool for Git operations"""

    def __init__(self, config: ToolsConfig):
        super().__init__(config)
        self.command_policy = CommandPolicy(['git'])

    async def execute(self, operation: str, **kwargs) -> ToolResult:
        try:
            if operation == "status":
                return await self._git_status()
            elif operation == "diff":
                return await self._git_diff(kwargs.get('file'))
            elif operation == "log":
                return await self._git_log(kwargs.get('limit', 10))
            elif operation == "branch":
                return await self._git_branch()
            else:
                return ToolResult(success=False, output="", error=f"Unknown git operation: {operation}")

        except Exception as e:
            return ToolResult(success=False, output="", error=str(e))
    
    async def _git_status(self) -> ToolResult:
        result = await self.command_policy.execute_safe(
            argv=['git', 'status', '--porcelain'],
            cwd=str(self.working_dir),
            timeout=30.0,
            risk_level="LOW"
        )

        return ToolResult(
            success=result['success'],
            output=result['stdout'],
            error=result['stderr'] if not result['success'] else None
        )
    
    async def _git_diff(self, file: Optional[str] = None) -> ToolResult:
        argv = ['git', 'diff']
        if file:
            # Validate file path to prevent injection
            if not self._validate_path(file):
                return ToolResult(success=False, output="", error=f"Invalid file path: {file}")
            argv.append(file)

        result = await self.command_policy.execute_safe(
            argv=argv,
            cwd=str(self.working_dir),
            timeout=30.0,
            risk_level="LOW"
        )

        return ToolResult(
            success=result['success'],
            output=result['stdout'],
            error=result['stderr'] if not result['success'] else None
        )
    
    async def _git_log(self, limit: int = 10) -> ToolResult:
        # Validate limit to prevent injection via format string
        if not isinstance(limit, int) or limit < 1 or limit > 1000:
            return ToolResult(success=False, output="", error=f"Invalid limit: {limit}")

        result = await self.command_policy.execute_safe(
            argv=['git', 'log', '--oneline', '-n', str(limit)],
            timeout=30.0,
            risk_level="LOW"
        )

        return ToolResult(
            success=result['success'],
            output=result['stdout'],
            error=result['stderr'] if not result['success'] else None
        )
    
    async def _git_branch(self) -> ToolResult:
        result = await self.command_policy.execute_safe(
            argv=['git', 'branch'],
            timeout=30.0,
            risk_level="LOW"
        )

        return ToolResult(
            success=result['success'],
            output=result['stdout'],
            error=result['stderr'] if not result['success'] else None
        )

class DirectoryListTool(BaseTool):
    """Tool for listing directory contents with filtering"""

    async def execute(self, path: str = ".", pattern: Optional[str] = None,
                     recursive: bool = False, show_hidden: bool = False) -> ToolResult:
        try:
            # Validate path is within working directory
            safe_path = self._safe_path(path)
            if safe_path is None:
                return ToolResult(
                    success=False,
                    output="",
                    error=f"Access denied: {path} is outside the working directory"
                )

            if not safe_path.exists():
                return ToolResult(success=False, output="", error=f"Path not found: {path}")

            if not safe_path.is_dir():
                return ToolResult(success=False, output="", error=f"Not a directory: {path}")

            # List contents
            entries = []
            if recursive:
                # Recursive listing
                for item in safe_path.rglob('*' if pattern is None else pattern):
                    if not show_hidden and item.name.startswith('.'):
                        continue
                    rel_path = item.relative_to(safe_path)
                    entry_type = 'dir' if item.is_dir() else 'file'
                    size = item.stat().st_size if item.is_file() else 0
                    entries.append(f"{entry_type:4} {size:>10} {rel_path}")
            else:
                # Non-recursive listing
                for item in safe_path.iterdir():
                    if not show_hidden and item.name.startswith('.'):
                        continue
                    if pattern and pattern not in item.name:
                        continue
                    entry_type = 'dir' if item.is_dir() else 'file'
                    size = item.stat().st_size if item.is_file() else 0
                    entries.append(f"{entry_type:4} {size:>10} {item.name}")

            output = '\n'.join(sorted(entries))

            return ToolResult(
                success=True,
                output=output,
                data={"path": str(safe_path), "count": len(entries)}
            )

        except Exception as e:
            return ToolResult(success=False, output="", error=str(e))

class FileSearchTool(BaseTool):
    """Tool for searching files by name/pattern"""

    async def execute(self, pattern: str, path: str = ".",
                     case_sensitive: bool = False, max_results: int = 100) -> ToolResult:
        log_debug(f"=== FileSearchTool.execute START ===")
        log_debug(f"  pattern='{pattern}'")
        log_debug(f"  path='{path}'")
        log_debug(f"  case_sensitive={case_sensitive}")
        log_debug(f"  max_results={max_results}")
        try:
            # Validate search path is within working directory
            log_debug(f"  Calling _safe_path('{path}')")
            safe_search_path = self._safe_path(path)
            log_debug(f"  safe_search_path='{safe_search_path}'")
            if safe_search_path is None:
                log_debug(f"  ERROR: safe_search_path is None, returning access denied")
                return ToolResult(
                    success=False,
                    output="",
                    error=f"Access denied: {path} is outside the working directory"
                )

            if not safe_search_path.exists():
                return ToolResult(success=False, output="", error=f"Path not found: {path}")

            # Search for matching files
            results = []
            search_pattern = pattern if case_sensitive else pattern.lower()
            log_debug(f"search_pattern='{search_pattern}'")

            # Use os.walk for safer traversal that doesn't follow symlinks or bind mounts
            mount_points = get_mount_points()
            log_debug(f"Detected mount points: {mount_points}")
            for root, dirs, files in os.walk(str(safe_search_path)):
                log_debug(f"os.walk - root='{root}'")
                # Prune hidden directories to avoid searching them
                dirs[:] = [d for d in dirs if not d.startswith('.')]
                log_debug(f"os.walk - dirs (after hidden prune)='{dirs}'")

                # Prune mount points (including binds) to prevent traversing external trees
                original_dirs = list(dirs)
                for d in original_dirs:
                    dir_path = os.path.join(root, d)
                    norm_dir_path = os.path.normpath(dir_path)
                    if norm_dir_path in mount_points and norm_dir_path != str(safe_search_path):
                        log_debug(f"Pruning mount point: {norm_dir_path}")
                        dirs.remove(d)
                
                for filename in files:
                    # Skip hidden files
                    if filename.startswith('.'):
                        continue

                    file_path = Path(root) / filename
                    
                    # The os.walk and mount pruning should prevent leaving the directory, 
                    # but this is a good defense-in-depth measure.
                    if not self._validate_path(str(file_path)):
                        log_debug(f"_validate_path failed for file: {file_path}")
                        continue

                    file_name_to_check = filename if case_sensitive else filename.lower()
                    log_debug(f"Checking file='{file_name_to_check}' against pattern='{search_pattern}'")

                    # Match pattern (glob or exact)
                    if '*' in search_pattern or '?' in search_pattern:
                        from fnmatch import fnmatch
                        if fnmatch(file_name_to_check, search_pattern):
                            results.append(str(file_path.relative_to(safe_search_path)))
                            log_debug(f"Glob match found: {file_path}")
                    else:
                        # Exact match for non-glob patterns
                        if search_pattern == file_name_to_check:
                            results.append(str(file_path.relative_to(safe_search_path)))
                            log_debug(f"Exact match found: {file_path}")
                    
                    if len(results) >= max_results:
                        log_debug(f"Max results reached ({max_results}). Breaking search.")
                        break
                if len(results) >= max_results:
                    break

                if len(results) >= max_results:
                    break

            output = '\n'.join(results)
            if len(results) >= max_results:
                output += f"\n\n[Truncated at {max_results} results]"

            log_debug(f"FileSearchTool returning {len(results)} results.")
            log_debug(f"FileSearchTool output: {output[:200]}...")

            return ToolResult(
                success=True,
                output=output,
                data={"matches": len(results), "truncated": len(results) >= max_results}
            )

        except Exception as e:
            log_debug(f"  EXCEPTION in FileSearchTool: {e}")
            import traceback
            log_debug(f"  Traceback: {traceback.format_exc()}")
            return ToolResult(success=False, output="", error=str(e))

class SystemInfoTool(BaseTool):
    """Tool for getting system resource information"""

    async def execute(self) -> ToolResult:
        try:
            import psutil
            import platform

            # CPU info
            cpu_percent = psutil.cpu_percent(interval=0.1)
            cpu_count = psutil.cpu_count()

            # Memory info
            memory = psutil.virtual_memory()
            memory_total = memory.total / (1024**3)  # GB
            memory_used = memory.used / (1024**3)
            memory_percent = memory.percent

            # Disk info for current working directory
            disk = psutil.disk_usage(str(self.working_dir))
            disk_total = disk.total / (1024**3)
            disk_used = disk.used / (1024**3)
            disk_percent = disk.percent

            output = f"""System Information:
CPU: {cpu_percent}% ({cpu_count} cores)
Memory: {memory_used:.1f}GB / {memory_total:.1f}GB ({memory_percent}%)
Disk: {disk_used:.1f}GB / {disk_total:.1f}GB ({disk_percent}%)
Platform: {platform.system()} {platform.release()}
Working Directory: {self.working_dir}
"""

            return ToolResult(
                success=True,
                output=output,
                data={
                    "cpu_percent": cpu_percent,
                    "cpu_count": cpu_count,
                    "memory_percent": memory_percent,
                    "disk_percent": disk_percent,
                    "working_dir": str(self.working_dir)
                }
            )

        except Exception as e:
            return ToolResult(success=False, output="", error=f"Failed to get system info: {e}")

class ResourceRequestTool(BaseTool):
    """Tool for requesting resource adjustments (model suggests, system decides)"""

    def __init__(self, config: ToolsConfig, interactive_mode=None):
        super().__init__(config)
        self.interactive_mode = interactive_mode  # Reference to InteractiveMode for resource adjustments

    async def execute(self, reason: str, estimated_complexity: str = "medium") -> ToolResult:
        """
        Model requests resource adjustment with justification.
        System makes the final decision based on smart allocation.

        Args:
            reason: Why model needs more resources (e.g., "large_file_search", "complex_analysis")
            estimated_complexity: Model's estimate ("low", "medium", "high")
        """
        try:
            # Map complexity to suggested percentage
            complexity_map = {
                "low": 25,
                "medium": 50,
                "high": 75,
                "critical": 100
            }

            requested_allocation = complexity_map.get(estimated_complexity.lower(), 50)

            # Get current allocation
            current_allocation = self.config.runtime.resources if hasattr(self.config, 'runtime') else 25

            # Determine if request is reasonable
            # System makes final decision based on:
            # 1. Current load
            # 2. Task type (reason)
            # 3. Hardware capabilities
            # 4. Requested vs current delta

            # For now, accept requests that are reasonable jumps
            if requested_allocation <= current_allocation:
                granted_allocation = current_allocation
                decision = "maintained"
            elif requested_allocation - current_allocation > 50:
                # Big jump - only grant partial
                granted_allocation = current_allocation + 25
                decision = "partially_granted"
            else:
                # Reasonable request
                granted_allocation = requested_allocation
                decision = "granted"

            output = f"""Resource Request Evaluated:
Reason: {reason}
Requested Complexity: {estimated_complexity} ({requested_allocation}%)
Current Allocation: {current_allocation}%
Decision: {decision.upper()}
Granted Allocation: {granted_allocation}%

Note: System retains final control over resource allocation based on hardware limits.
"""

            return ToolResult(
                success=True,
                output=output,
                data={
                    "reason": reason,
                    "requested": requested_allocation,
                    "granted": granted_allocation,
                    "decision": decision
                }
            )

        except Exception as e:
            return ToolResult(success=False, output="", error=f"Resource request failed: {e}")

class ChangeDirectoryTool(BaseTool):
    """Tool for changing working directory with confirmation"""

    async def execute(self, new_path: str) -> ToolResult:
        try:
            new_path_obj = Path(new_path).resolve()

            # Validate that the new path exists and is a directory
            if not new_path_obj.exists():
                return ToolResult(
                    success=False,
                    output="",
                    error=f"Directory does not exist: {new_path}"
                )

            if not new_path_obj.is_dir():
                return ToolResult(
                    success=False,
                    output="",
                    error=f"Path is not a directory: {new_path}"
                )

            # Confirmation handled by orchestrator (MEDIUM risk)
            # If we reach here, user has confirmed
            old_dir = self.working_dir

            # NOTE: This only updates THIS tool's working_dir
            # The ToolManager needs to propagate this change to ALL tools
            # See execute_tool() special handling for change_directory

            return ToolResult(
                success=True,
                output=f"Working directory changed from {old_dir} to {new_path_obj}",
                data={"old_dir": str(old_dir), "new_dir": str(new_path_obj), "new_path": str(new_path_obj)}
            )

        except Exception as e:
            return ToolResult(success=False, output="", error=str(e))

class FileCopyTool(BaseTool):
    """Tool for copying files"""

    async def execute(self, source: str, destination: str, overwrite: bool = False) -> ToolResult:
        try:
            from shutil import copy2
            source_path = self._safe_path(source)
            dest_path = self._safe_path(destination)

            if source_path is None or dest_path is None:
                return ToolResult(success=False, output="", error="Access denied: path is outside the working directory")

            if not source_path.exists():
                return ToolResult(success=False, output="", error=f"Source file not found: {source}")

            if dest_path.exists() and not overwrite:
                return ToolResult(success=False, output="", error=f"Destination exists: {destination}. Use overwrite=true to replace.")

            copy2(source_path, dest_path)
            return ToolResult(
                success=True,
                output=f"Copied {source} to {destination}",
                data={"source": str(source_path), "destination": str(dest_path)}
            )

        except Exception as e:
            return ToolResult(success=False, output="", error=f"Copy failed: {e}")

class FileMoveTool(BaseTool):
    """Tool for moving/renaming files"""

    async def execute(self, source: str, destination: str) -> ToolResult:
        try:
            from shutil import move
            source_path = self._safe_path(source)
            dest_path = self._safe_path(destination)

            if source_path is None or dest_path is None:
                return ToolResult(success=False, output="", error="Access denied: path is outside the working directory")

            if not source_path.exists():
                return ToolResult(success=False, output="", error=f"Source file not found: {source}")

            move(str(source_path), str(dest_path))
            return ToolResult(
                success=True,
                output=f"Moved {source} to {destination}",
                data={"source": str(source_path), "destination": str(dest_path)}
            )

        except Exception as e:
            return ToolResult(success=False, output="", error=f"Move failed: {e}")

class FileDeleteTool(BaseTool):
    """Tool for deleting files (IRREVERSIBLE)"""

    async def execute(self, file_path: str) -> ToolResult:
        try:
            path = self._safe_path(file_path)
            if path is None:
                return ToolResult(success=False, output="", error="Access denied: path is outside the working directory")

            if not path.exists():
                return ToolResult(success=False, output="", error=f"File not found: {file_path}")

            if path.is_dir():
                return ToolResult(success=False, output="", error=f"Cannot delete directory. Use bash_execute with 'rm -r' if needed.")

            path.unlink()
            return ToolResult(
                success=True,
                output=f"Deleted {file_path}",
                data={"deleted_file": str(path)}
            )

        except Exception as e:
            return ToolResult(success=False, output="", error=f"Delete failed: {e}")

class FileCreateTool(BaseTool):
    """Tool for creating new empty files"""

    async def execute(self, file_path: str, content: str = "") -> ToolResult:
        try:
            path = self._safe_path(file_path)
            if path is None:
                return ToolResult(success=False, output="", error="Access denied: path is outside the working directory")

            if path.exists():
                return ToolResult(success=False, output="", error=f"File already exists: {file_path}. Use file_write or file_fill to modify.")

            path.parent.mkdir(parents=True, exist_ok=True)
            path.write_text(content)

            return ToolResult(
                success=True,
                output=f"Created {file_path}" + (f" with {len(content)} chars" if content else " (empty)"),
                data={"file_path": str(path), "size": len(content)}
            )

        except Exception as e:
            return ToolResult(success=False, output="", error=f"Create failed: {e}")

class FileFillTool(BaseTool):
    """Tool for filling/appending to files"""

    async def execute(self, file_path: str, content: str, mode: str = "overwrite") -> ToolResult:
        try:
            path = self._safe_path(file_path)
            if path is None:
                return ToolResult(success=False, output="", error="Access denied: path is outside the working directory")

            if mode not in ["overwrite", "append"]:
                return ToolResult(success=False, output="", error=f"Invalid mode '{mode}'. Use 'overwrite' or 'append'.")

            path.parent.mkdir(parents=True, exist_ok=True)

            if mode == "append":
                with open(path, 'a') as f:
                    f.write(content)
                action = "Appended to"
            else:
                path.write_text(content)
                action = "Filled"

            return ToolResult(
                success=True,
                output=f"{action} {file_path} with {len(content)} chars",
                data={"file_path": str(path), "mode": mode, "size": len(content)}
            )

        except Exception as e:
            return ToolResult(success=False, output="", error=f"Fill failed: {e}")

class ProcessManageTool(BaseTool):
    """Tool for managing system processes"""

    async def execute(self, operation: str, pid: int = None, pattern: str = None) -> ToolResult:
        try:
            import psutil

            if operation == "list":
                processes = []
                for proc in psutil.process_iter(['pid', 'name', 'cpu_percent', 'memory_percent']):
                    try:
                        if pattern and pattern.lower() not in proc.info['name'].lower():
                            continue
                        processes.append(f"PID {proc.info['pid']}: {proc.info['name']} (CPU: {proc.info['cpu_percent']}%, MEM: {proc.info['memory_percent']:.1f}%)")
                    except (psutil.NoSuchProcess, psutil.AccessDenied):
                        continue

                output = "\n".join(processes[:50])  # Limit to 50 processes
                return ToolResult(success=True, output=output, data={"count": len(processes)})

            elif operation == "info":
                if not pid:
                    return ToolResult(success=False, output="", error="PID required for 'info' operation")

                proc = psutil.Process(pid)
                info = f"""Process {pid}:
Name: {proc.name()}
Status: {proc.status()}
CPU: {proc.cpu_percent()}%
Memory: {proc.memory_percent():.1f}%
Threads: {proc.num_threads()}
"""
                return ToolResult(success=True, output=info, data={"pid": pid, "name": proc.name()})

            elif operation == "kill":
                if not pid:
                    return ToolResult(success=False, output="", error="PID required for 'kill' operation")

                proc = psutil.Process(pid)
                name = proc.name()
                proc.terminate()
                return ToolResult(success=True, output=f"Terminated process {pid} ({name})", data={"pid": pid, "name": name})

            else:
                return ToolResult(success=False, output="", error=f"Invalid operation '{operation}'. Use: list, info, kill")

        except psutil.NoSuchProcess:
            return ToolResult(success=False, output="", error=f"Process {pid} not found")
        except psutil.AccessDenied:
            return ToolResult(success=False, output="", error=f"Permission denied for process {pid}")
        except Exception as e:
            return ToolResult(success=False, output="", error=f"Process operation failed: {e}")

class WebSearchTool(BaseTool):
    """Tool for searching the web via duckduckgo_search library"""

    async def execute(self, query: str, max_results: int = 5) -> ToolResult:
        try:
            # Use duckduckgo_search library (proper API wrapper, no CAPTCHA)
            from duckduckgo_search import DDGS

            results = []
            with DDGS() as ddgs:
                search_results = ddgs.text(query, max_results=max_results)

                for result in search_results:
                    title = result.get('title', '')
                    body = result.get('body', '')
                    href = result.get('href', '')

                    if title and body:
                        results.append(f"• {title}\n  {body}\n  Source: {href}")

            if not results:
                return ToolResult(
                    success=False,
                    output="",
                    error=f"No search results found for '{query}'"
                )

            return ToolResult(
                success=True,
                output=f"Search results for '{query}':\n\n" + "\n\n".join(results),
                data={"query": query, "result_count": len(results)}
            )

        except ImportError:
            # Fallback: Simple message if library not installed
            return ToolResult(
                success=False,
                output="",
                error="Web search requires 'duckduckgo-search' library. Install with: pip install duckduckgo-search"
            )
        except Exception as e:
            return ToolResult(success=False, output="", error=f"Web search failed: {e}")

class WebFetchTool(BaseTool):
    """Tool for fetching web content"""

    async def execute(self, url: str, extract_text: bool = True) -> ToolResult:
        try:
            import httpx
            from bs4 import BeautifulSoup

            async with httpx.AsyncClient() as client:
                response = await client.get(url, timeout=15.0, follow_redirects=True)
                response.raise_for_status()

            if extract_text:
                soup = BeautifulSoup(response.text, 'html.parser')
                # Remove script and style elements
                for script in soup(["script", "style"]):
                    script.decompose()
                text = soup.get_text()
                # Clean up whitespace
                lines = (line.strip() for line in text.splitlines())
                output = '\n'.join(line for line in lines if line)
            else:
                output = response.text

            # Limit output size
            if len(output) > 5000:
                output = output[:5000] + "\n... (truncated)"

            return ToolResult(
                success=True,
                output=output,
                data={"url": url, "status": response.status_code, "size": len(output)}
            )

        except Exception as e:
            return ToolResult(success=False, output="", error=f"Web fetch failed: {e}")

class CodeAnalyzeTool(BaseTool):
    """Tool for analyzing code syntax and structure"""

    async def execute(self, file_path: str = None, code: str = None, language: str = "python") -> ToolResult:
        try:
            if file_path:
                path = Path(file_path).resolve()
                if not path.exists():
                    return ToolResult(success=False, output="", error=f"File not found: {file_path}")
                code = path.read_text()
                if not language or language == "auto":
                    language = path.suffix[1:]  # Extract from extension

            if not code:
                return ToolResult(success=False, output="", error="Either file_path or code parameter required")

            analysis = {
                "lines": len(code.splitlines()),
                "chars": len(code),
                "language": language
            }

            # Basic syntax check for Python
            if language == "python":
                try:
                    import ast
                    tree = ast.parse(code)
                    analysis["syntax"] = "valid"
                    analysis["functions"] = len([n for n in ast.walk(tree) if isinstance(n, ast.FunctionDef)])
                    analysis["classes"] = len([n for n in ast.walk(tree) if isinstance(n, ast.ClassDef)])
                except SyntaxError as e:
                    analysis["syntax"] = "invalid"
                    analysis["error"] = str(e)

            output = f"""Code Analysis ({language}):
Lines: {analysis['lines']}
Characters: {analysis['chars']}
Syntax: {analysis.get('syntax', 'not checked')}
"""
            if 'functions' in analysis:
                output += f"Functions: {analysis['functions']}\n"
            if 'classes' in analysis:
                output += f"Classes: {analysis['classes']}\n"
            if 'error' in analysis:
                output += f"Error: {analysis['error']}\n"

            return ToolResult(success=True, output=output, data=analysis)

        except Exception as e:
            return ToolResult(success=False, output="", error=f"Code analysis failed: {e}")

class PackageCheckTool(BaseTool):
    """Tool for checking package dependencies"""

    async def execute(self, package_name: str = None, file_path: str = None) -> ToolResult:
        try:
            import subprocess

            if package_name:
                # Check if specific package is installed
                result = subprocess.run(
                    ['pip', 'show', package_name],
                    capture_output=True,
                    text=True,
                    timeout=10
                )

                if result.returncode == 0:
                    output = f"Package '{package_name}' is installed:\n{result.stdout}"
                else:
                    output = f"Package '{package_name}' not found"

                return ToolResult(success=True, output=output, data={"package": package_name, "installed": result.returncode == 0})

            elif file_path:
                # Check requirements file
                path = Path(file_path).resolve()
                if not path.exists():
                    return ToolResult(success=False, output="", error=f"File not found: {file_path}")

                requirements = path.read_text().strip().splitlines()
                output = f"Found {len(requirements)} requirements in {file_path}:\n"
                output += "\n".join(f"- {req}" for req in requirements[:20])

                return ToolResult(success=True, output=output, data={"file": str(path), "count": len(requirements)})

            else:
                # List all installed packages
                result = subprocess.run(
                    ['pip', 'list', '--format=columns'],
                    capture_output=True,
                    text=True,
                    timeout=15
                )

                lines = result.stdout.splitlines()
                output = "\n".join(lines[:30])  # First 30 packages

                return ToolResult(success=True, output=output, data={"count": len(lines) - 2})  # Minus header lines

        except subprocess.TimeoutExpired:
            return ToolResult(success=False, output="", error="Package check timed out")
        except Exception as e:
            return ToolResult(success=False, output="", error=f"Package check failed: {e}")

class ThinkTimeTool(BaseTool):
    """Tool for requesting extended thinking time with user confirmation"""

    async def execute(self, seconds: int, reason: str = "Deep analysis required") -> ToolResult:
        """Request extended thinking time from user.

        Args:
            seconds: Number of seconds requested for thinking (30-900)
            reason: Explanation of why extended time is needed

        Returns:
            ToolResult with approval status and allocated time
        """
        try:
            from rich.console import Console
            from rich.prompt import Confirm

            console = Console()

            # Validate seconds range
            if not (30 <= seconds <= 900):
                return ToolResult(
                    success=False,
                    output="",
                    error="Think time must be between 30 and 900 seconds"
                )

            # Request user confirmation (MEDIUM risk - needs confirmation)
            console.print(f"\n[cyan]🧠 Model requests {seconds}s thinking time:[/cyan]")
            console.print(f"[dim]Reason: {reason}[/dim]")

            approved = Confirm.ask(f"[yellow]Grant {seconds}s extended thinking time?[/yellow]")

            if not approved:
                return ToolResult(
                    success=False,
                    output="Think time request denied by user",
                    error="User cancelled think time request"
                )

            # Approved - return success with time allocation
            output = f"Think time granted: {seconds}s for {reason}"

            return ToolResult(
                success=True,
                output=output,
                data={
                    "seconds_granted": seconds,
                    "reason": reason,
                    "resource_level": 75,  # Increase to 75% for thinking
                    "mode": "think"
                }
            )

        except Exception as e:
            return ToolResult(
                success=False,
                output="",
                error=f"Think time request failed: {e}"
            )

class ToolManager:
    """Manager for all available tools"""

    def __init__(self, config: ToolsConfig):
        self.config = config
        self._cache = {}  # Tool result cache: {cache_key: (result, timestamp)}
        self._cache_hits = 0
        self._cache_misses = 0
        self.tools = {
            # Original tools
            "file_read": FileReadTool(config),
            "read_text": FileReadTool(config),  # Alias - models often use this
            "file_write": FileWriteTool(config),
            "file_edit": FileEditTool(config),
            "bash_execute": BashExecuteTool(config),
            "grep_search": GrepSearchTool(config),
            "git_operations": GitOperationsTool(config),
            "change_directory": ChangeDirectoryTool(config),
            "directory_list": DirectoryListTool(config),
            "file_search": FileSearchTool(config),
            "system_info": SystemInfoTool(config),
            "resource_request": ResourceRequestTool(config),
            # New tools
            "file_copy": FileCopyTool(config),
            "file_move": FileMoveTool(config),
            "file_delete": FileDeleteTool(config),
            "file_create": FileCreateTool(config),
            "file_fill": FileFillTool(config),
            "process_manage": ProcessManageTool(config),
            "web_search": WebSearchTool(config),
            "web_fetch": WebFetchTool(config),
            "code_analyze": CodeAnalyzeTool(config),
            "package_check": PackageCheckTool(config),
            "think_time": ThinkTimeTool(config)
        }
        self._working_dir = Path.cwd().resolve()

    @property
    def working_dir(self):
        """Get the current working directory"""
        return self._working_dir

    @working_dir.setter
    def working_dir(self, value: Path):
        """Set working directory and propagate to all tools"""
        self._working_dir = value
        # Update all tools' working directories
        for tool in self.tools.values():
            tool.working_dir = value
    
    def get_available_tools(self) -> List[str]:
        """Get list of available tools"""
        return [tool for tool in self.tools.keys() if tool in self.config.enabled]

    def get_tool_descriptions(self) -> str:
        """Get brief tool descriptions for dynamic system prompt injection"""
        descriptions = {
            'file_read': 'file_read(file_path, start_line, end_line) - Read file contents',
            'file_write': 'file_write(file_path, content) - Create/overwrite file',
            'file_edit': 'file_edit(file_path, old_content, new_content) - Edit file by replacing text',
            'file_copy': 'file_copy(source, destination) - Copy files or directories',
            'file_move': 'file_move(source, destination) - Move/rename files or directories',
            'file_delete': 'file_delete(file_path) - Delete files (requires confirmation)',
            'file_create': 'file_create(file_path, content) - Create new file with content',
            'file_search': 'file_search(pattern, path, file_type, max_results, recursive) - Find files by name pattern',
            'directory_list': 'directory_list(path, show_hidden, recursive, max_depth) - List directory contents',
            'change_directory': 'change_directory(path) - Change working directory',
            'grep_search': 'grep_search(pattern, path, file_pattern, context_lines, ignore_case, recursive) - Search text inside files',
            'code_analyze': 'code_analyze(file_path, analysis_type) - Analyze code (structure|complexity|dependencies|security)',
            'package_check': 'package_check(package_name, package_manager) - Check if package installed (pip|npm|cargo|apt)',
            'bash_execute': 'bash_execute(command, timeout, check, cwd, env) - Execute shell commands',
            'process_manage': 'process_manage(action, process_id, signal) - Manage processes (list|kill|info)',
            'git_operations': 'git_operations(operation, args, path, message) - Git commands (status|diff|log|add|commit|push|pull|clone|branch|checkout)',
            'web_search': 'web_search(query, max_results) - Search web via DuckDuckGo',
            'web_fetch': 'web_fetch(url, method, headers, data) - Fetch web content with HTTP requests',
            'system_info': 'system_info(info_type) - Get system info (os|cpu|memory|disk|network|all)',
            'resource_request': 'resource_request(requested_resources, reason) - Request additional computational resources',
        }

        enabled = self.get_available_tools()
        lines = []

        # Tool list
        for tool in enabled:
            if tool in descriptions:
                lines.append(f"  - {descriptions[tool]}")

        # Add path context AFTER tools
        lines.append("\n  CURRENT_DIRECTORY: " + str(self.working_dir))
        lines.append("\n  PATH WORKFLOW:")
        lines.append("  - Unknown file? Use file_search first to locate it")
        lines.append("  - File not found? Use directory_list to check current directory")
        lines.append("  - All paths are relative to CURRENT_DIRECTORY above")

        return "\n".join(lines) if lines else "  (No tools available)"

