    async def execute_tool(self, tool_name: str, **kwargs) -> ToolResult:
        """Execute a tool with given parameters, applying caching, retry, and confirmation"""
        # NOTE: Do NOT auto-sync from OS CWD - working_dir is explicitly managed
        # by commands like /coding new. Syncing from Path.cwd() would override
        # the intentionally-set experiment directory.

        if tool_name not in self.config.enabled:
            # Provide helpful hint about available tools
            available = ', '.join(list(self.tools.keys())[:5])
            hint = f"'{tool_name}' is NOT a tool or correct format. Try something else. Available tools include: {available}"
            return ToolResult(success=False, output="", error=f"Tool not enabled: {tool_name}\n\nHINT: {hint}")

        if tool_name not in self.tools:
            # Provide helpful hint about available tools
            available = ', '.join(list(self.tools.keys())[:5])
            hint = f"'{tool_name}' is NOT a tool or correct format. Try something else. Available tools include: {available}"
            return ToolResult(success=False, output="", error=f"Tool not found: {tool_name}\n\nHINT: {hint}")

        # Argument normalization/safety nets
        try:
            if tool_name == 'file_write':
                # Map 'path' → 'file_path' if provided
                if 'file_path' not in kwargs and 'path' in kwargs:
                    kwargs['file_path'] = kwargs.pop('path')
                # Default content if missing
                if 'content' not in kwargs:
                    kwargs['content'] = ""
        except Exception:
            pass

        # Check cache for read-only operations
        cache_key = None
        if getattr(self.config, 'cache_results', False):
            cacheable_tools = ['file_read', 'directory_list', 'grep_search', 'system_info', 'package_check']
            if tool_name in cacheable_tools:
                import hashlib
                import time
                # Create cache key from tool name + args
                cache_key = f"{tool_name}:{hashlib.md5(str(sorted(kwargs.items())).encode()).hexdigest()}"

                if cache_key in self._cache:
                    cached_result, timestamp = self._cache[cache_key]
                    cache_ttl = getattr(self.config, 'cache_ttl', 300)
                    if time.time() - timestamp < cache_ttl:
                        self._cache_hits += 1
                        # Return cached result
                        return cached_result
                    else:
                        # Expired - remove from cache
                        del self._cache[cache_key]

                self._cache_misses += 1

        # Execute tool with retry logic
        tool = self.tools[tool_name]
        max_retries = getattr(self.config, 'max_retries', 2) if getattr(self.config, 'auto_retry', False) else 0

        result = None
        last_error = None
        for attempt in range(max_retries + 1):
            try:
                result = await tool.execute(**kwargs)

                if result.success:
                    break  # Success - no need to retry
                else:
                    last_error = result.error
                    # Don't retry if user explicitly cancelled the operation
                    if last_error and "cancelled by user" in last_error.lower():
                        break  # User cancellation is final - don't retry
                    if attempt < max_retries:
                        # Retry on failure
                        continue
            except Exception as e:
                last_error = str(e)
                if attempt < max_retries:
                    continue
                else:
                    result = ToolResult(success=False, output="", error=str(e))

        # Cache successful result
        if cache_key and result and result.success:
            import time
            self._cache[cache_key] = (result, time.time())

        # Special handling for change_directory - propagate to all tools
        if tool_name == 'change_directory' and result and result.success:
            new_path = result.data.get('new_path')
            if new_path:
                self.working_dir = Path(new_path)  # Uses setter to propagate to all tools

        return result if result else ToolResult(success=False, output="", error=last_error or "Unknown error")
    
    def get_tool_description(self, tool_name: str) -> str:
        """Get description of a tool"""
        descriptions = {
            "file_read": "Read contents of a file",
            "file_write": "Write content to a file",
            "file_edit": "Edit a file by replacing text",
            "bash_execute": "Execute bash commands",
            "grep_search": "Search for patterns in files",
            "git_operations": "Perform Git operations"
        }
        return descriptions.get(tool_name, "Unknown tool")
    
    def get_tools_help(self) -> str:
        """Get help text for all available tools"""
        help_text = "Available tools:\n\n"
        for tool_name in self.get_available_tools():
            help_text += f"- {tool_name}: {self.get_tool_description(tool_name)}\n"
        return help_text

    def get_cache_stats(self) -> Dict[str, Any]:
        """Get tool cache statistics"""
        return {
            'enabled': getattr(self.config, 'cache_results', False),
            'cache_size': len(self._cache),
            'cache_hits': self._cache_hits,
            'cache_misses': self._cache_misses,
            'hit_rate': f"{(self._cache_hits / max(1, self._cache_hits + self._cache_misses) * 100):.1f}%",
            'ttl_seconds': getattr(self.config, 'cache_ttl', 300)
        }

    def clear_cache(self):
        """Clear tool result cache"""
        self._cache.clear()
        self._cache_hits = 0
        self._cache_misses = 0

    def enable_tool(self, tool_name: str) -> bool:
        """Enable a tool at runtime"""
        if tool_name not in self.tools:
            return False  # Tool doesn't exist

        if tool_name not in self.config.enabled:
            self.config.enabled.append(tool_name)
            return True
        return False  # Already enabled

    def disable_tool(self, tool_name: str) -> bool:
        """Disable a tool at runtime"""
        if tool_name in self.config.enabled:
            self.config.enabled.remove(tool_name)
            return True
        return False  # Not enabled

    def is_tool_enabled(self, tool_name: str) -> bool:
        """Check if a tool is enabled"""
        return tool_name in self.config.enabled

    def get_all_tool_names(self) -> List[str]:
        """Get all tool names (enabled and disabled)"""
        return list(self.tools.keys())
